// client/src/components/Header.jsx (updated to use AuthContext)
import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext'; // Import useAuth
import './Header.css';

const Header = () => {
    const { user, logout } = useAuth(); // Get user and logout function
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login'); // Redirect to login after logout
    };

    return (
        <header className="header">
            <div className="header-container">
                <Link to="/" className="logo">My Electroo</Link>
                
                <nav className="nav-links">
                    <Link to="/products">Products</Link>
                    <Link to="/cart">Cart</Link>
                    <p className='into'>...One stop for your all electronic products</p>
                    {user ? ( // Check if user is logged in
                        <>
                            <Link to="/profile">Profile</Link> {/* You'd create a ProfilePage */}
                            {user.role === 'admin' && <Link to="/admin">Admin</Link>} {/* Check for admin role */}
                            <button onClick={handleLogout} className="nav-btn">Logout</button>
                        </>
                    ) : (
                        <>
                            <Link to="/login">Login</Link>
                            <Link to="/register">Register</Link>
                        </>
                    )}
                </nav>
            </div>
        </header>
    );
};

export default Header;
